class MinHeap {
    private var heap: [Int]
    init(arr: [Int]) {
        heap = arr
        buildHeap()
    }

    private func buildHeap() {
        for i in stride(from: (heap.count/2)-1, through: 0, by: -1) {
            siftDown(i)
        }
    }

    func top() -> Int? {
        return heap.first
    }

    func pop() {
        guard !heap.isEmpty else { return }
        heap.swapAt(0, heap.count-1)
        heap.removeLast()
        if !heap.isEmpty {
            siftDown(0)
        }
    }

    private func siftDown(_ index: Int) {
        var idx = index
        while true {
            let left = 2 * idx + 1
            let right = 2 * idx + 2
            var smallest = idx

            if left < heap.count && heap[left] < heap[smallest] {
                smallest = left
            }
            if right < heap.count && heap[right] < heap[smallest] {
                smallest = right
            }
            if smallest == idx {
                break
            }
            heap.swapAt(idx, smallest)
            idx = smallest
        }
    }
}

func find(_ x: Int, _ parent: inout [Int]) -> Int {
    var node = x
    while node != parent[node] {
        node = parent[node]
    }
    let root = node
    var temp = x
    while temp != root {
        let next = parent[temp]
        parent[temp] = root
        temp = next
    }
    return root
}

func solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let cInt = Int(c)
    var parent = Array(0...cInt)
    let connectionsInt: [[Int]] = connections.map { $0.map { Int($0) } }
    let queriesInt: [[Int]] = queries.map { $0.map { Int($0) } }

    for connection in connectionsInt {
        let u = connection[0]
        let v = connection[1]
        let rootU = find(u, &parent)
        let rootV = find(v, &parent)
        if rootU != rootV {
            if rootU < rootV {
                parent[rootV] = rootU
            } else if rootV < rootU {
                parent[rootU] = rootV
            }
        }
    }

    var rep = Array(repeating: 0, count: cInt+1)
    for i in 1...cInt {
        rep[i] = find(i, &parent)
    }

    var compLists = [Int: [Int]]()
    for i in 1...cInt {
        let root = rep[i]
        compLists[root, default: []].append(i)
    }

    var compHeap = [Int: MinHeap]()
    for (root, list) in compLists {
        compHeap[root] = MinHeap(arr: list)
    }

    var online = Array(repeating: true, count: cInt+1)
    var result = [Int64]()

    for query in queriesInt {
        let op = query[0]
        let x = query[1]
        if op == 1 {
            if online[x] {
                result.append(Int64(x))
            } else {
                let root = rep[x]
                if let heap = compHeap[root] {
                    while let topValue = heap.top(), online[topValue] == false {
                        heap.pop()
                    }
                    if let topValue = heap.top(), online[topValue] == true {
                        result.append(Int64(topValue))
                    } else {
                        result.append(-1)
                    }
                } else {
                    result.append(-1)
                }
            }
        } else if op == 2 {
            if online[x] {
                online[x] = false
            }
        }
    }

    return result
}
```

### Explanation
1. **MinHeap Initialization:** 
   - The `MinHeap` class is initialized with all nodes of a component. The heap property ensures the smallest node is always at the top, which is crucial for efficiently retrieving the smallest online node.

2. **Union-Find for Component Identification:**
   - The `find` function uses path compression to keep the DSU efficient. The root of each component is the smallest node in that component, simplifying the process of finding the smallest online node later.

3. **Component Processing:**
   - After processing connections to form components, each node is mapped to its component root. Nodes in each component are stored in a min-heap.

4. **Query Handling:**
   - For type `1` queries, if the queried station is online, it directly responds. Otherwise, the smallest online station in its component is found by removing offline stations from the heap top until a valid station is found or the heap is empty.
   - For type `2` queries, the station is marked offline. Actual heap removal is deferred to subsequent type `1` queries for efficiency.

This approach efficiently handles the dynamic offline operations and queries by leveraging the DSU for connectivity and min-heaps with lazy deletion for maintaining the smallest online nodes in components. The complexity is optimized through path compression and heap operations.

To solve this problem, we need to efficiently handle two types of queries on a dynamic graph where nodes can be taken offline. The graph remains structurally fixed, meaning connections between nodes do not change, but nodes can be marked as offline. For each query of type `[1, x]`, we need to determine the smallest online node in the connected component of node `x` if `x` is offline; otherwise, `x` handles the query itself. 

### Approach
1. **Union-Find Data Structure**: We use the Union-Find (Disjoint Set Union, DSU) data structure to preprocess the initial graph connections. This helps in efficiently determining the connected component (or root) of any node.
2. **Linked List per Component**: For each connected component, we maintain a sorted linked list of its nodes. This allows us to efficiently track the smallest online node in the component. The head of this linked list always points to the smallest online node in the component.
3. **Handling Queries**:
   - **Query Type 1 (`[1, x]`)**:
     - If node `x` is online, it handles the query.
     - If `x` is offline, we check the head of its component's linked list. If the head is `nil` (indicating no online nodes in the component), we return -1; otherwise, we return the head node.
   - **Query Type 2 (`[2, x]`)**:
     - If node `x` is online, we mark it as offline and remove it from its component's linked list. This involves updating the previous and next pointers of neighboring nodes in the linked list and updating the head of the component if `x` was the head.

