func solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let n = Int(c)
    if n == 0 {
        return []
    }

    var parent = Array(0...n)
    var rank = Array(repeating: 0, count: n+1)

    func find(_ x: Int) -> Int {
        if parent[x] != x {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    for edge in connections {
        let u = Int(edge[0])
        let v = Int(edge[1])
        let ru = find(u)
        let rv = find(v)
        if ru == rv {
            continue
        }
        if rank[ru] < rank[rv] {
            parent[ru] = rv
        } else if rank[ru] > rank[rv] {
            parent[rv] = ru
        } else {
            parent[rv] = ru
            rank[ru] += 1
        }
    }

    var rootId = Array(0...n)
    for i in 1...n {
        rootId[i] = find(i)
    }

    var groups: [Int: [Int]] = [:]
    for i in 1...n {
        let r = rootId[i]
        groups[r, default: []].append(i)
    }

    var nextOnline = [Int?](repeating: nil, count: n+1)
    var prevOnline = [Int?](repeating: nil, count: n+1)
    var compHead = [Int?](repeating: nil, count: n+1)
    var online = Array(repeating: true, count: n+1)

    for (root, nodes) in groups {
        let sortedList = nodes.sorted()
        compHead[root] = sortedList.first
        for j in 0..<sortedList.count-1 {
            let u = sortedList[j]
            let v = sortedList[j+1]
            nextOnline[u] = v
            prevOnline[v] = u
        }
    }

    var ans: [Int64] = []
    for query in queries {
        let type = query[0]
        let x = query[1]
        let xInt = Int(x)

        if type == 1 {
            if online[xInt] {
                ans.append(x)
            } else {
                let root = rootId[xInt]
                if let head = compHead[root] {
                    ans.append(Int64(head))
                } else {
                    ans.append(-1)
                }
            }
        } else if type == 2 {
            if online[xInt] {
                online[xInt] = false
                let root = rootId[xInt]
                let prev = prevOnline[xInt]
                let next = nextOnline[xInt]

                if let p = prev {
                    nextOnline[p] = next
                } else {
                    compHead[root] = next
                }

                if let n = next {
                    prevOnline[n] = prev
                }
            }
        }
    }

    return ans
}
```

### Explanation
1. **Initialization**: We start by initializing the Union-Find structure (`parent` and `rank` arrays) to manage connected components.
2. **Processing Connections**: Using the connections array, we merge nodes into their respective connected components using the Union-Find algorithm.
3. **Root Identification**: For each node, we determine its root (representative of its connected component) and group nodes by their roots.
4. **Linked List Construction**: For each connected component, we sort the nodes and construct a linked list where each node points to the next node in sorted order. The head of the list is the smallest node in the component.
5. **Query Processing**:
   - For **Query Type 1**, if the queried node is online, it handles the query. Otherwise, the head of its component's linked list is returned (or -1 if no online nodes exist in the component).
   - For **Query Type 2**, the node is marked offline and removed from its component's linked list by updating neighboring nodes' pointers and the component's head if necessary.
6. **Result Compilation**: The results for all queries of type 1 are compiled into an array and returned.

This approach efficiently handles dynamic offline operations and queries by leveraging Union-Find for connectivity and linked lists for tracking the smallest online nodes in each component. The operations are optimized for performance, ensuring scalability for large inputs.

To solve this problem, we need to efficiently handle two types of queries on a dynamic graph where nodes can be marked offline. The graph is static in terms of connectivity, but nodes can go offline, affecting the results of certain queries. The key challenge is to quickly determine the smallest online node in a connected component for query type `[1, x]` and to mark nodes offline for query type `[2, x]`.

### Approach
1. **Graph Construction and Component Identification**: 
   - Construct the graph using an adjacency list from the given connections.
   - Use BFS to identify connected components. Each node is assigned a component ID. This helps in grouping nodes into their respective connected components.

2. **Priority Queues for Components**:
   - For each connected component, maintain a max-heap (simulated using min-heap by storing negative values) of node identifiers. This allows efficient retrieval of the smallest online node in the component.

3. **Handling Queries**:
   - **Query Type `[1, x]`**:
     - If the node `x` is online, the result is `x`.
     - If the node `x` is offline, clean the heap of the component by removing offline nodes from the top until an online node is found or the heap is empty. The top of the cleaned heap (if any) is the smallest online node in the component.
   - **Query Type `[2, x]`**:
     - Mark the node `x` as offline. No immediate heap modification is needed; offline nodes are lazily removed during query processing.

