func solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>): Array<Int64> {
    import std.collections.VecDeque
    import std.collections.BinaryHeap

    let c_usize = c.to_usize()
    var graph = Array.replicate(c_usize + 1, Array.empty<Int64>())
    for conn in connections {
        let u = conn[0]
        let v = conn[1]
        graph[u.to_usize()] = graph[u.to_usize()].append(v)
        graph[v.to_usize()] = graph[v.to_usize()].append(u)
    }

    var comp_id = Array.replicate(c_usize + 1, 0)
    var comp_heaps = Array.empty<BinaryHeap<Int64>>()
    var comp_index = 1

    for i from 1 to c_usize {
        if comp_id[i] == 0 {
            var queue = VecDeque.empty<Int64>()
            queue.push_back(i.to_int64())
            comp_id[i] = comp_index
            var heap = BinaryHeap.empty<Int64>()
            heap.push(-(i.to_int64()))
            while not queue.is_empty() {
                let node = queue.pop_front().unwrap()
                for nbor in graph[node.to_usize()] {
                    let n_idx = nbor.to_usize()
                    if comp_id[n_idx] == 0 {
                        comp_id[n_idx] = comp_index
                        heap.push(-nbor)
                        queue.push_back(nbor)
                    }
                }
            }
            comp_heaps = comp_heaps.append(heap)
            comp_index = comp_index + 1
        }
    }

    var online = Array.replicate(c_usize + 1, true)
    var result = Array.empty<Int64>()

    for query in queries {
        let ty = query[0]
        let x = query[1]
        if ty == 1 {
            if online[x.to_usize()] {
                result = result.append(x)
            } else {
                let comp = comp_id[x.to_usize()] - 1
                if comp >= comp_heaps.length() {
                    result = result.append(-1)
                } else {
                    let heap = &comp_heaps[comp]
                    var cleaned = false
                    while not heap.is_empty() {
                        let stored = heap.peek().unwrap()
                        let node = -stored
                        if online[node.to_usize()] {
                            cleaned = true
                            break
                        } else {
                            heap.pop()
                        }
                    }
                    if heap.is_empty() {
                        result = result.append(-1)
                    } else {
                        let stored = heap.peek().unwrap()
                        let node = -stored
                        result = result.append(node)
                    }
                }
            }
        } else if ty == 2 {
            online[x.to_usize()] = false
        }
    }

    return result
}
```

### Explanation
- **Graph Construction**: The graph is built from the given connections using an adjacency list. Each connection is bidirectional, so both directions are added to the adjacency list.
- **Component Identification**: Using BFS, nodes are traversed to identify connected components. Each node is assigned a component ID, and a max-heap (storing negative values to simulate a min-heap) is created for each component to keep track of node identifiers.
- **Query Processing**:
  - **Type `[1, x]`**: If `x` is online, the result is `x`. If offline, the component's heap is cleaned by removing offline nodes from the top. The smallest remaining online node (if any) is the answer.
  - **Type `[2, x]`**: The node `x` is marked offline. The heap is not modified immediately; offline nodes are removed lazily during subsequent queries.
- **Efficiency**: The BFS runs in O(N + M) time for N nodes and M edges. Each heap operation (insert, remove) is O(log N), and each query processes offline nodes lazily, ensuring efficient handling of large inputs. The solution efficiently manages dynamic offline statuses and component queries.

To solve this problem, we need to efficiently handle two types of queries on a dynamically changing graph where nodes can be turned offline. The key challenge is to quickly determine the smallest online node in the connected component of a queried node, especially when nodes are being turned offline over time.

### Approach
1. **Graph Construction**: Build an adjacency list to represent the graph of connected nodes.
2. **Connected Components Identification**: Using Depth-First Search (DFS), identify all connected components in the graph. For each component, determine the smallest node (original minimum) which will serve as the component identifier.
3. **Linked List Initialization**: For each connected component, create a sorted linked list of its nodes. This linked list helps in efficiently tracking the smallest online node in the component. The head of this linked list starts as the smallest node in the component.
4. **Processing Queries**:
   - **Query Type 1 (Check Maintenance)**: If the queried node is online, it resolves the query itself. If offline, the head of its component's linked list (smallest online node) resolves the query. If no online nodes exist in the component, return -1.
   - **Query Type 2 (Turn Offline)**: When a node is turned offline, update the linked list of its component by removing the node and adjusting the head if the removed node was the head.
5. **Efficiency**: The use of linked lists per component ensures that removing a node and updating the head is done in constant time, making the solution efficient for large inputs.

