```swift
func solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let n_nodes = Int(c)
    var adj = [[Int64]](repeating: [], count: n_nodes+1)
    for conn in connections {
        let u = conn[0]
        let v = conn[1]
        adj[Int(u)].append(v)
        adj[Int(v)].append(u)
    }

    var visited = [Bool](repeating: false, count: n_nodes+1)
    var comp_id = [Int64](repeating: 0, count: n_nodes+1)
    var next_online = [Int64](repeating: -1, count: n_nodes+1)
    var prev_online = [Int64](repeating: -1, count: n_nodes+1)
    var head_of_comp = [Int64](repeating: -1, count: n_nodes+1)
    var online = [Bool](repeating: true, count: n_nodes+1)

    for i in 1...n_nodes {
        if visited[i] { continue }

        var stack = [Int64]()
        stack.append(Int64(i))
        visited[i] = true
        var component = [Int64]()
        while !stack.isEmpty {
            let u = stack.removeLast()
            component.append(u)
            for v in adj[Int(u)] {
                let idx_v = Int(v)
                if !visited[idx_v] {
                    visited[idx_v] = true
                    stack.append(v)
                }
            }
        }

        let min_node = component.min()!
        let sortedComp = component.sorted()
        head_of_comp[Int(min_node)] = sortedComp[0]

        for node in component {
            comp_id[Int(node)] = min_node
        }

        let n_comp = sortedComp.count
        for j in 0..<n_comp {
            let u = sortedComp[j]
            if j == 0 {
                prev_online[Int(u)] = -1
            } else {
                prev_online[Int(u)] = sortedComp[j-1]
            }
            if j == n_comp-1 {
                next_online[Int(u)] = -1
            } else {
                next_online[Int(u)] = sortedComp[j+1]
            }
        }
    }

    var res = [Int64]()
    for q in queries {
        let type = q[0]
        let x = q[1]
        let idx_x = Int(x)

        if type == 1 {
            if online[idx_x] {
                res.append(x)
            } else {
                let comp_x = comp_id[idx_x]
                let head = head_of_comp[Int(comp_x)]
                if head == -1 {
                    res.append(-1)
                } else {
                    res.append(head)
                }
            }
        } else if type == 2 {
            if online[idx_x] {
                online[idx_x] = false
                let comp_x = comp_id[idx_x]
                let prev = prev_online[idx_x]
                let next = next_online[idx_x]
                if prev != -1 {
                    next_online[Int(prev)] = next
                } else {
                    head_of_comp[Int(comp_x)] = next
                }
                if next != -1 {
                    prev_online[Int(next)] = prev
                }
            }
        }
    }

    return res
}
```

### Explanation
1. **Graph Construction**: The graph is built using an adjacency list where each node points to its connected neighbors.
2. **Component Identification**: Using DFS, we traverse each node to identify all connected components. For each component, we note the smallest node (original minimum) which acts as the component identifier.
3. **Linked List Setup**: For each component, we create a sorted linked list where each node points to the next and previous nodes in the sorted order. The head of this list is initialized to the smallest node in the component.
4. **Query Handling**:
   - **Type 1 (Check)**: If the node is online, it resolves the query. If offline, the head of its component's linked list (smallest online node) resolves it. If no online nodes exist, return -1.
   - **Type 2 (Turn Offline)**: When a node is turned offline, it is removed from its component's linked list. The head is updated if the removed node was the head.
5. **Efficiency**: The solution efficiently handles dynamic changes (turning nodes offline) and queries by maintaining linked lists per component, ensuring updates and queries are processed in constant or logarithmic time relative to the component size. This approach is optimal for large-scale inputs as specified.
